package main

import "fmt"

func onesCount(x int) int {
    cnt := 0
    for x > 0 {
        cnt += x & 1
        x >>= 1
    }
    return cnt
}

func countPopInSet(n int64, T_map map[int]bool) int64 {
    s := fmt.Sprintf("%b", n)
    L := len(s)

    dp := make([][][]int64, L+1)
    for i := 0; i <= L; i++ {
        dp[i] = make([][]int64, 2)
        for tight := 0; tight < 2; tight++ {
            dp[i][tight] = make([]int64, L+1)
        }
    }

    dp[0][1][0] = 1

    for i := 0; i < L; i++ {
        for tight := 0; tight < 2; tight++ {
            for cnt := 0; cnt <= L; cnt++ {
                if dp[i][tight][cnt] == 0 {
                    continue
                }
                limit := 1
                if tight == 1 {
                    limit = int(s[i] - '0')
                }
                for d := 0; d <= limit; d++ {
                    new_tight := tight
                    if tight == 1 && d < limit {
                        new_tight = 0
                    }
                    new_cnt := cnt
                    if d == 1 {
                        new_cnt = cnt + 1
                    }
                    if new_cnt <= L {
                        dp[i+1][new_tight][new_cnt] += dp[i][tight][cnt]
                    }
                }
            }
        }
    }

    var ans int64
    for tight := 0; tight < 2; tight++ {
        for cnt := 0; cnt <= L; cnt++ {
            if T_map[cnt] {
                ans += dp[L][tight][cnt]
            }
        }
    }
    return ans
}

func solve(n int64, k int64) int64 {
    if k == 0 {
        if n < 1 {
            return 0
        }
        return 1
    }

    D := make([]int, 61)
    D[1] = 0
    for i := 2; i <= 60; i++ {
        p := onesCount(i)
        D[i] = 1 + D[p]
    }

    T_map := make(map[int]bool)
    for a := 1; a <= 60; a++ {
        if D[a] == int(k-1) {
            T_map[a] = true
        }
    }

    total := countPopInSet(n, T_map)
    if k == 1 {
        total -= 1
    }

    return total
}
```

### Explanation
1. **Precomputation**:
   - The `onesCount` function calculates the number of set bits in an integer.
   - The `D` array stores the popcount-depth for integers 1 to 60. For each integer `i`, `D[i] = 1 + D[popcount(i)]`, starting with `D[1] = 0`.

2. **Digit Dynamic Programming**:
   - **Binary Conversion**: Convert `n` to its binary string representation.
   - **DP State**: `dp[i][tight][cnt]` represents the count of numbers processed up to bit `i` (0-indexed), where `tight` indicates if the current prefix matches `n`'s prefix, and `cnt` is the number of set bits so far.
   - **State Transitions**: For each bit position, iterate over possible bits (0 or 1), updating the tight constraint and count of set bits. The transitions accumulate counts based on whether the current bit is within the limit imposed by `n`.

3. **Result Calculation**:
   - For `k = 0`, return 1 if `n >= 1` (only the number 1 qualifies).
   - For `k ≥ 1`, count numbers in `[1, n]` whose popcount is in the set `T` (integers `a` with `depth[a] = k-1`). Subtract 1 if `k = 1` to exclude the number 1.

This approach efficiently counts the required numbers using digit DP and precomputed depths, leveraging constraints on `k` to ensure optimal performance.

