func solve(n int64, k int64) int64 {
    if k == 0 {
        return 1
    }

    depthArr := make([]int, 61)
    depthArr[1] = 0
    for i := 2; i <= 60; i++ {
        t := i
        pop := 0
        for t > 0 {
            pop += t & 1
            t >>= 1
        }
        depthArr[i] = 1 + depthArr[pop]
    }

    inS := make([]bool, 61)
    target := int(k - 1)
    for i := 1; i <= 60; i++ {
        if depthArr[i] == target {
            inS[i] = true
        }
    }

    total := digitDP(n, inS)
    if k == 1 {
        total--
    }
    return total
}

func digitDP(n int64, inS []bool) int64 {
    binStr := ""
    if n == 0 {
        binStr = "0"
    } else {
        t := n
        for t > 0 {
            if t % 2 == 0 {
                binStr = "0" + binStr
            } else {
                binStr = "1" + binStr
            }
            t /= 2
        }
    }
    L := len(binStr)

    dp := make([][][]int64, L+1)
    for i := range dp {
        dp[i] = make([][]int64, 2)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 61)
        }
