    dp[0][1][0] = 1

    for i := 0; i < L; i++ {
        for tight := 0; tight < 2; tight++ {
            for cnt := 0; cnt <= 60; cnt++ {
                if dp[i][tight][cnt] == 0 {
                    continue
                }
                low := 0
                high := 1
                if tight == 1 {
                    if binStr[i] == '0' {
                        high = 0
                    } else {
                        high = 1
                    }
                }
                for b := low; b <= high; b++ {
                    newCnt := cnt
                    if b == 1 {
                        newCnt = cnt + 1
                    }
                    if newCnt > 60 {
                        continue
                    }
                    newTight := 0
                    if tight == 1 {
