                            newTight = 1
                        }
                    }
                    dp[i+1][newTight][newCnt] += dp[i][tight][cnt]
                }
            }
        }
    }

    var total int64
    for tight := 0; tight < 2; tight++ {
        for cnt := 1; cnt <= 60; cnt++ {
            if inS[cnt] {
                total += dp[L][tight][cnt]
            }
        }
    }
    return total
}
