import (
    "math/bits"
    "fmt"
)

func solve(n int64, k int64) int64 {
    if k == 0 {
        return 1
    }

    const maxN = 1000
    dep := make([]int, maxN+1)
    dep[1] = 0
    for i := 2; i <= maxN; i++ {
        pop := bits.OnesCount(uint(i))
        dep[i] = 1 + dep[pop]
    }

    S := make(map[int]bool)
    for c := 1; c <= 50; c++ {
        if dep[c] == int(k)-1 {
            S[c] = true
        }
    }

    total := countByPopcount(n, S)

    if k == 1 {
        total--
    }

    return total
}

func countByPopcount(n int64, S map[int]bool) int64 {
    bin := fmt.Sprintf("%b", n)
    L := len(bin)

    dp := make([][][]int64, L+1)
    for i := range dp {
        dp[i] = make([][]int64, 2)
        for j := range dp[i] {
            dp[i][j] = make([]int64, L+1)
        }
    }

    for tight := 0; tight < 2; tight++ {
        for cnt := 0; cnt <= L; cnt++ {
            if S[cnt] {
                dp[L][tight][cnt] = 1
            } else {
                dp[L][tight][cnt] = 0
            }
        }
    }

    for i := L - 1; i >= 0; i-- {
        for tight := 0; tight < 2; tight++ {
            for cnt := 0; cnt <= L; cnt++ {
                total := int64(0)
                up := 1
                if tight == 1 {
                    up = int(bin[i] - '0')
                }
                for d := 0; d <= up; d++ {
                    newTight := 0
                    if tight == 1 {
                        if d == up {
                            newTight = 1
                        } else {
                            newTight = 0
                        }
                    }
                    newCnt := cnt
                    if d == 1 {
                        if cnt < L {
                            newCnt = cnt + 1
                        } else {
                            continue
                        }
                    }
                    total += dp[i+1][newTight][newCnt]
                }
                dp[i][tight][cnt] = total
            }
        }
    }
    return dp[0][1][0]
}
```

